mapper.insert:
INSERT INTO XBOLTDLM.COMTNFILE
  	 ( ATCH_FILE_ID 
  	 , CREAT_DT
  	 , USE_AT
  	 )
VALUES
	 ( #{AtchFileId}
	 , GETDATE()
	 , 'Y'
	 )

INSERT INTO XBOLTDLM.COMTNFILEDETAIL
  	 ( ATCH_FILE_ID 
  	 , FILE_SN
  	 , FILE_STRE_COURS
  	 , STRE_FILE_NM
  	 , ORIGNL_FILE_NM
  	 , FILE_EXTSN
  	 , FILE_CN
  	 , FILE_SIZE
  	 )
VALUES
	 ( #{AtchFileId}
	 , #{FileSn}
	 , #{FilePath}
	 , #{FileRealNm}
	 , #{FileNm}
	 , #{FileExt}
	 , NULL
	 , #{FileSize}
	 )

mapper.select:
SELECT ORIGNL_FILE_NM FROM XBOLTDLM.COMTNFILEDETAIL
WHERE FILE_SN = #{seq}
AND ATCH_FILE_ID = #{AtchFileId}

SELECT STRE_FILE_NM FROM XBOLTDLM.COMTNFILEDETAIL
WHERE FILE_SN = #{seq}
AND ATCH_FILE_ID = #{AtchFileId}

SELECT FILE_STRE_COURS FROM XBOLTDLM.COMTNFILEDETAIL
WHERE FILE_SN = #{seq}
AND ATCH_FILE_ID = #{AtchFileId}

SELECT STRE_FILE_NM as filename, FILE_STRE_COURS+STRE_FILE_NM as downFile, ORIGNL_FILE_NM  as original
FROM XBOLTDLM.COMTNFILEDETAIL
WHERE FILE_SN = #{seq}
AND ATCH_FILE_ID = #{AtchFileId}

mapper.delete:
DELETE XBOLTDLM.COMTNFILEDETAIL
 WHERE ATCH_FILE_ID = #{atchFileId}
   AND FILE_SN = #{Seq}
